      CALL TSAT2_CFG(2, (IBRCH(9)+29), (IBRCH(9)+30), (IBRCH(9)+31), (IB&
     &RCH(9)+32), (IBRCH(9)+33), (IBRCH(9)+1),0,0,0,0,0,0,SS(9),RVD1_1,0&
